#import "WBAboutHeaderView.h"
#import "WBWebViewController.h"
#import "WBAppManager.h"
#import "WBFeedbackViewController.h"

@interface WBAboutViewController () <UITableViewDelegate, UITableViewDataSource>

@property(nonatomic, strong) WBAboutHeaderView *headerView;
@property(nonatomic, strong) UITableView *tableView;
@property(nonatomic, strong) UIView *bottomView;
@property(nonatomic, strong) UIView *seperatorView;
@property(nonatomic, strong) UIButton *privacyPolicyButton;
@property(nonatomic, strong) UIButton *serviceContractButton;

@end

@implementation WBAboutViewController

static NSString * reuseIdentifier = @"Cell";

- (void)jun_routeBuild:(JUNRouteBuilder *)route {
    [route name:@"privacy" handle:^(NSDictionary * _Nullable userInfo, JUNRouterNextHandler  _Nonnull next) {
        [self privacyPolicyButtonClicked];
    }];
    [route name:@"terms" handle:^(NSDictionary * _Nullable userInfo, JUNRouterNextHandler  _Nonnull next) {
        [self serviceContractButtonClicked];
    }];
}

- (instancetype)init {
    if (self = [super init]) {
        self.hidesBottomBarWhenPushed = YES;
    }
    return self;
}

- (void)viewDidLoad {
    [super viewDidLoad];
    self.title = NSLocalizedString(@"关于", nil);
    self.view.backgroundColor = WBColorHex(0xF0F0F0);
    [self setUpUI];
}


#pragma mark - setUpUI

- (void)setUpUI {
    [self addAllSubviews];
    [self addAllConstraints];
}

- (void)addAllSubviews {
    [self.view addSubview:self.headerView];
    [self.view addSubview:self.tableView];
    [self.view addSubview:self.bottomView];
    [self.bottomView addSubview:self.seperatorView];
    [self.bottomView addSubview:self.privacyPolicyButton];
    [self.bottomView addSubview:self.serviceContractButton];
}

- (void)addAllConstraints {
    [_headerView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.view).offset(ZOOM(108));
        make.left.right.equalTo(self.view);
        make.height.mas_equalTo(ZOOM(150));
    }];

    [_tableView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.headerView.mas_bottom).offset(ZOOM(20));
        make.left.right.equalTo(self.view);
        make.height.mas_equalTo(ZOOM(180));
    }];

    [_bottomView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.left.right.bottom.equalTo(self.view);
        make.height.mas_equalTo(ZOOM(100));
    }];

    [_seperatorView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.centerX.equalTo(self.bottomView);
        make.top.equalTo(self.bottomView).offset(ZOOM(20));
        make.width.mas_equalTo(ZOOM(1));
        make.height.mas_equalTo(ZOOM(8));
    }];

    [_privacyPolicyButton mas_makeConstraints:^(MASConstraintMaker *make) {
        if ([WBAppManager sharedManager].isRTL) {
            make.left.equalTo(self.seperatorView.mas_right).offset(ZOOM(16));
        } else {
            make.right.equalTo(self.seperatorView.mas_left).offset(ZOOM(-16));
        }
        make.centerY.equalTo(self.seperatorView);
        make.height.mas_equalTo(ZOOM(21));
    }];

    [_serviceContractButton mas_makeConstraints:^(MASConstraintMaker *make) {
        if ([WBAppManager sharedManager].isRTL) {
            make.right.equalTo(self.seperatorView.mas_left).offset(ZOOM(-16));
        } else {
            make.left.equalTo(self.seperatorView.mas_right).offset(ZOOM(16));
        }
        make.centerY.equalTo(self.seperatorView);
        make.height.mas_equalTo(ZOOM(21));
    }];
}


#pragma mark - events

- (void)privacyPolicyButtonClicked {
    [self _showWebVcWithURL:[self _getPrivacyURLStr] title:NSLocalizedString(@"隐私政策", nil)];
}

- (void)serviceContractButtonClicked {
    [self _showWebVcWithURL:[self _getTermsURLStr] title:NSLocalizedString(@"服务协议", nil)];
}

- (NSString *)_getPrivacyURLStr {
    return [WBSettingManager sharedManager].PrivacyURL;
}

- (NSString *)_getTermsURLStr {
    return [WBSettingManager sharedManager].UserTermURL;
}

- (void)_showWebVcWithURL:(NSString *)urlStr title:(NSString *)title {
    NSURL *url = [NSURL URLWithString:urlStr];
    NSParameterAssert(url != nil);
    WBWebViewController *webVC = [[WBWebViewController alloc] initWithURL:url];
    webVC.title = title;
    [self.navigationController pushViewController:webVC animated:YES];
}


#pragma mark - lazy load

- (WBAboutHeaderView *)headerView {
    if (!_headerView) {
        _headerView = [[WBAboutHeaderView alloc] init];
    }
    return _headerView;
}

- (UITableView *)tableView {
    if (_tableView == nil) {
        _tableView = [[UITableView alloc] initWithFrame:CGRectZero style:UITableViewStylePlain];
        _tableView.wb_width = self.view.wb_width;
        _tableView.separatorStyle = UITableViewCellSeparatorStyleNone;
        _tableView.backgroundColor = [UIColor clearColor];
        _tableView.rowHeight = WBRpt(58.0);
        _tableView.delegate = self;
        _tableView.dataSource = self;
        _tableView.scrollEnabled = NO;
        [_tableView registerClass:[WBAboutCell class] forCellReuseIdentifier:reuseIdentifier];
    }
    return _tableView;
}


// 底部隐私政策和服务协议视图
- (UIView *)bottomView {
    if (_bottomView == nil) {
        _bottomView = [[UIView alloc] init];
        _bottomView.backgroundColor = [UIColor clearColor];
    }
    return _bottomView;
}

- (UIView *)seperatorView {
