- (void)showUpdateAlertWithUpdateInfo:(NSDictionary *)updateInfo shouldUpdate:(BOOL)shouldUpdate {
    NSString *titleString = shouldUpdate ? NSLocalizedString(@"App Store有新版本可用", nil) : NSLocalizedString(@"当前已是最新版本", nil);
    NSString *contentString = shouldUpdate ? NSLocalizedString(@"\n有新版本可用，建议前往App Store进行更新，以获得更好的产品体验", nil) : NSLocalizedString(@"\n无需更新", nil);
    UIAlertController *alertController = [UIAlertController alertControllerWithTitle:titleString message:contentString preferredStyle:UIAlertControllerStyleAlert];

    if (shouldUpdate) {
        NSNumber *tidNum = [updateInfo[@"trackId"] isKindOfClass:[NSNumber class]] ? updateInfo[@"trackId"] : nil;
        NSString *tid = tidNum ? tidNum.stringValue : nil;

        UIAlertAction *laterAction = [UIAlertAction actionWithTitle:NSLocalizedString(@"稍后再说", nil) style:UIAlertActionStyleDefault handler:nil];
        [alertController addAction:laterAction];
        [laterAction setValue:[UIColor grayColor] forKey:@"titleTextColor"];
        UIAlertAction *updateAction = [UIAlertAction actionWithTitle:NSLocalizedString(@"前往更新", nil) style:UIAlertActionStyleDefault handler:^(UIAlertAction * _Nonnull action) {
            if (tid) {
                [WBAppManager.sharedManager viewAppDetailInAppStore:tid];
            } else {
                [SVProgressHUD showErrorWithStatus:NSLocalizedString(@"跳转地址错误", nil)];
            }
        }];
        [alertController addAction:updateAction];
    } else {
        UIAlertAction *iknowAction = [UIAlertAction actionWithTitle:NSLocalizedString(@"我知道了", nil) style:UIAlertActionStyleDefault handler:nil];
        [alertController addAction:iknowAction];
    }

    [[WBAppManager getUIApplicationCurrentViewController] presentViewController:alertController animated:YES completion:nil];
}


