- (void)handleSkip {
    [WBEventManager logReferralActivitywithCode:@"skip"];
    [WBEventManager flushEvents];
    if (self.isInApp) {
        // 在App内部，使用pop
        [self.navigationController popViewControllerAnimated:YES];
    } else {
        // 登录流程中，调用dismissBlock让上层处理
        if (self.dismissBlock) {
            self.dismissBlock();
        }
    }
}

- (void)handleConfirm {
    [self.view endEditing:YES];

    if (!WBReferralManager.sharedManager.activityStart) {
        [SVProgressHUD showInfoWithStatus:@"活动未开启"];
        return;
    }

    // 防空：检查输入是否为空
    NSString *code = [self.codeTextfield.text stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceAndNewlineCharacterSet]];
    if (code.length == 0) {
        [SVProgressHUD showErrorWithStatus:NSLocalizedString(@"请输入邀请码", nil)];
        return;
    }

    // 防抖：防止重复提交
    if (self.isSubmitting) {
        NSLog(@"beidangzhule");
        return;
    }

    self.isSubmitting = YES;
    [SVProgressHUD show];

    [[WBNetworkManager defaultManager] sendReferralCode:@([code longLongValue])  callback:^(id  _Nullable json, NSError * _Nullable error) {
        self.isSubmitting = NO;
        [SVProgressHUD dismiss];

        if (error) {
            NSString *descriptionStr =  error.userInfo[@"NSLocalizedDescription"];
            [SVProgressHUD showErrorWithStatus:descriptionStr];
        } else {
            // 刷新邀请数据
            [[WBReferralManager sharedManager] refreshReferralData];
            if (json && ![json isKindOfClass:[NSNull class]]) {

                if (self.isInApp) {
                    [WBEventManager logReferralActivitywithCode:@"confirmB"];
                }else {
                    [WBEventManager logReferralActivitywithCode:@"confirmA"];
                }
                [WBEventManager flushEvents];
                WBUserInfoHttpModel *model = [WBUserInfoHttpModel modelWithJSON:json[@"vipInfoVo"]];
                [WBSettingManager.sharedManager syncWithUserInfo:model];
                // 如果有路由，在dismiss后执行
                if (json && [json[@"route"][@"type"] integerValue] == 1) {
                    NSDictionary *routeData = json[@"route"][@"data"];
                    NSString *link = routeData[@"link"];
                    NSURL *url = [NSURL URLWithString:link];
                    if (url) {
                        dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(0.3 * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
                            [[WBRouteManager sharedManager] performRoute:url sourceInterface:@"referral/register"];
                        });
                    }
                }
            } else {
                [SVProgressHUD showInfoWithStatus:@"活动未开启"];
            }
        }
        PostNotificationOnMainThread(WBAccountStatusChangedNotification, nil);
    }];
}

- (void)handleRewardConfirm {
    [self.navigationController popViewControllerAnimated:YES];
    if (self.dismissBlock) {
        dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(0.3 * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
            self.dismissBlock();
        });
    }
}

- (BOOL)isValidInviteCode:(NSString *)code {
    NSRegularExpression *regex = [NSRegularExpression regularExpressionWithPattern:@"^\\d{6}$" options:0 error:nil];
    NSRange range = NSMakeRange(0, code.length);
    return [regex firstMatchInString:code options:0 range:range] != nil;
}


