@property(atomic, readwrite) uint32_t appUsedTimeInSecond;
@property(nonatomic, readwrite) BOOL enabled;
@property(nonatomic, readonly) uint32_t heartbeatInterval;
@property(nonatomic, readonly) uint32_t reportInterval;

@property(nonatomic, strong) NSMutableDictionary<NSNumber*, NSMutableDictionary<NSString*, NSNumber*>*> *mergeableEventCounts;

@end

@implementation WBEventManager

+ (WBEventManager*)defaultManager {
    static WBEventManager* instance;
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        instance = [[WBEventManager alloc] init];
    });
    return instance;
}

- (instancetype)init {
    self = [super init];
    if (self) {
        _queue = dispatch_queue_create("__eventqueue", NULL);
        _eventList = [[NSMutableArray alloc] init];
        _lastReportTime = 0;
        _vappUsedTimeInSecond = 0;
        _enabled = FALSE;
        _mergeableEventCounts = [[NSMutableDictionary alloc] init];
        dispatch_async([self queue], ^{
            [self processEventList];
            [self vappUsageRecord];
        });
        [self load];
    }
    return self;
}

