    // TODO:
}

- (uint32_t)heartbeatInterval {
    if (WBSettingManager.sharedManager.HeartBeatRate) {
        return (uint32_t)WBSettingManager.sharedManager.HeartBeatRate;
    }
    return 15;
}

- (uint32_t)reportInterval {
    if (WBSettingManager.sharedManager.LogRate) {
        return (uint32_t)WBSettingManager.sharedManager.LogRate;
    }
    return 5;
}

- (void)vappUsageRecord {
    //    NSLog(@"timer");
    _appUsedTimeInSecond += 1;
    if (vapp_is_running()) {
        _vappUsedTimeInSecond += 1;
    }
    if (_vappUsedTimeInSecond >= self.heartbeatInterval || _appUsedTimeInSecond >= self.heartbeatInterval) {
        [self doHeartBeatWithUsageReport];
    }
    dispatch_after(dispatch_time_delay(1), [self queue], ^{
        [self vappUsageRecord];
    });
}

- (void)doHeartBeatWithUsageReport {
    dispatch_async([self queue], ^{
        NSMutableDictionary *dataDict = [@{
            @"v" : @(self.vappUsedTimeInSecond),
            @"a" : @(self.appUsedTimeInSecond)
        } mutableCopy];

        if ([WBAppManager sharedManager].launchingVappVid != 0) {
            dataDict[@"i"] = @([WBAppManager sharedManager].launchingVappVid);
        }

        [WBEventManager addEventWithType:eventTypeAppHeartBeat data:dataDict];
        self.vappUsedTimeInSecond = 0;
        self.appUsedTimeInSecond = 0;
    });

    // do event action request
    dispatch_async(dispatch_get_main_queue(), ^{
        if (WBAppManager.sharedManager.isActive) {
            if (vapp_is_running()) {
                [[WBActionRequestManager sharedManager] requestReportEventWithType:WBActionRequestEventTypeVappRunningInForeground defaultHandler:nil];
            } else {
                [[WBActionRequestManager sharedManager] requestReportEventWithType:WBActionRequestEventTypeAppRunningInForeground defaultHandler:nil];
            }
        } else {
            if (vapp_is_running()) {
                [[WBActionRequestManager sharedManager] requestReportEventWithType:WBActionRequestEventTypeVappRunningInBackground defaultHandler:nil];
            } else {
                [[WBActionRequestManager sharedManager] requestReportEventWithType:WBActionRequestEventTypeAppRunningInBackground defaultHandler:nil];
            }
        }
    });
}

- (void)processEventList {
    if (CFAbsoluteTimeGetCurrent()-_lastReportTime >= self.reportInterval) {
        [self doProcessEventList];
    }

    // process the queue every 1 sec
    dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(1 * NSEC_PER_SEC)), [self queue], ^{
        [self processEventList];
    });
}

- (void)doProcessEventList {
    if (_enabled == FALSE) {
        return;
    }

    for (NSNumber *eventTypeKey in [_mergeableEventCounts allKeys]) {
        NSMutableDictionary *codeCounts = _mergeableEventCounts[eventTypeKey];
        if ([codeCounts count] > 0) {
