- (void)showIntroHighlightOnButton:(UIButton *)button {

    if ([self.view viewWithTag:9999]) return;

    [self.view layoutIfNeeded];

    CGRect buttonFrame = [self.view convertRect:button.bounds fromView:button];

    UIView *mask = [[UIView alloc] init];
    mask.tag = 9999;
    mask.backgroundColor = [UIColor clearColor];
    mask.frame = self.view.bounds;
    [self.view addSubview:mask];

    UITapGestureRecognizer *tap = [[UITapGestureRecognizer alloc] initWithTarget:self action:@selector(hideIntroMask)];
    [mask addGestureRecognizer:tap];

    CAShapeLayer *maskLayer = [CAShapeLayer layer];
    maskLayer.fillRule = kCAFillRuleEvenOdd;
    maskLayer.fillColor = [UIColor colorWithWhite:0 alpha:0.6].CGColor;

    UIBezierPath *outerPath = [UIBezierPath bezierPathWithRect:mask.bounds];

    CGFloat holeSize = ZOOM(45);
    CGFloat cornerRadius = ZOOM(12);
    CGPoint center = CGPointMake(CGRectGetMidX(buttonFrame), CGRectGetMidY(buttonFrame));
    CGRect holeRect = CGRectMake(center.x - holeSize/2, center.y - holeSize/2, holeSize, holeSize);
    UIBezierPath *holePath = [UIBezierPath bezierPathWithRoundedRect:holeRect cornerRadius:cornerRadius];

    [outerPath appendPath:holePath];
    maskLayer.path = outerPath.CGPath;

    mask.layer.mask = nil;
    [mask.layer addSublayer:maskLayer];

    UIImageView *arrowImageView = [[UIImageView alloc] initWithImage:[UIImage imageNamed:@"Guide_introArrow2"]];
    if ([WBAppManager sharedManager].isRTL) {
        arrowImageView.transform = CGAffineTransformMakeScale(-1, 1);
    }
    [mask addSubview:arrowImageView];
    [arrowImageView mas_makeConstraints:^(MASConstraintMaker *make) {
        if ([WBAppManager sharedManager].isRTL) {
            make.left.equalTo(button.mas_right).offset(ZOOM(20));
        } else {
            make.right.equalTo(button.mas_left).offset(ZOOM(-20));
        }
        make.centerY.equalTo(button);
        make.height.mas_equalTo(ZOOM(44));
        make.width.mas_equalTo(ZOOM(60));
    }];

    UILabel *tipLabel = [[UILabel alloc] init];
    tipLabel.text = NSLocalizedString(@"点击以输入邀请码", nil);
    tipLabel.textColor = [UIColor blackColor];
    tipLabel.backgroundColor = [UIColor whiteColor];
    tipLabel.font = WBPrimaryBoldFont(18);
    tipLabel.layer.cornerRadius = ZOOM(12);
    tipLabel.clipsToBounds = YES;
    tipLabel.textAlignment = NSTextAlignmentCenter;
    [mask addSubview:tipLabel];
    [tipLabel mas_makeConstraints:^(MASConstraintMaker *make) {
        if ([WBAppManager sharedManager].isRTL) {
            make.left.equalTo(button).offset(ZOOM(-10));
        } else {
            make.right.equalTo(button).offset(ZOOM(10));
        }
        make.top.equalTo(button.mas_bottom).offset(ZOOM(20));
        make.height.mas_equalTo(ZOOM(45));
        make.width.mas_equalTo(ZOOM(268));
    }];

    UIButton *OKButton = [[UIButton alloc] init];
    [OKButton setTitle:NSLocalizedString(@"好的", nil) forState:UIControlStateNormal];
    [OKButton setTitleColor:[UIColor blackColor] forState:UIControlStateNormal];
    OKButton.backgroundColor = [UIColor whiteColor];
    OKButton.layer.cornerRadius = ZOOM(27);
    [OKButton addTarget:self action:@selector(hideIntroMask) forControlEvents:UIControlEventTouchUpInside];

    [mask addSubview:OKButton];
    [OKButton mas_makeConstraints:^(MASConstraintMaker *make) {
        make.right.left.equalTo(mask).inset(ZOOM(37));

    if (_dashLineView.layer.sublayers.count > 0) {
